const body = $input.first().json.body;
const taskId = body.sessionId || ('task_' + Date.now() + '_' + Math.random().toString(36).slice(2, 8));

// 初始化静态数据存储
const staticData = $getWorkflowStaticData('global');
if (!staticData.tasks) {
  staticData.tasks = {};
}

// 保存初始任务状态
staticData.tasks[taskId] = {
  status: 'processing',
  stepName: '',
  message: '工作流已启动，正在生成内容...',
  preview: null,
  previewHistory: [],
  allowRevise: false,
  allowConfirm: false,
  xhsImages: [],
  currentImageIndex: 0,
  history: [],
  createdAt: Date.now()
};

return {
  json: {
    success: true,
    taskId: taskId,
    status: 'processing',
    message: '工作流已启动，正在生成内容...'
  }
};

